data_path = pathlib.Path(ann_root)
with data_path.open(encoding='utf-8') as f:
    annotation = json.load(f)

for index in range(len(annotation)):
    sample = annotation[index]
    video_name = sample['video'].split('/')[-1]
    video_path = os.path.join(vis_root, video_name)
    if 'Normal' in video_path:
        video_label_vad = 0
    else:
        video_label_vad = 1
    # conversation_list = sample['QA']

    vlen = sample['length'] + 1
    start, end = 0, vlen

    indices = []

    # random_integers = np.arange(start, end, (end - start) / self.num_sampled_frame).astype(int).tolist()
    random_integers = np.arange(start, end, (end - start) / (end - start)).astype(int).tolist()
    sorted_integers = np.sort(random_integers)
    indices += sorted_integers.tolist()

    # Pick frame indices and create a list of 4-frame groups
    frame_no_list = [str(i) + '.jpg' for i in indices]

    frame_path_list = [video_path + '/' + frame_idx for frame_idx in frame_no_list]
    video_name = [video_name]


    # frame_path_list, video_label_vad, video_name = batch

    print(index)

    batch_end_frame = len(frame_path_list)
    batch_center_frame_idxs = range(
        0, batch_end_frame, 30
    )
    batch_clip_frame_paths = _prepare_frame_data(
        vis_root + "/" + video_name[0], len(frame_path_list), batch_center_frame_idxs, 30
    )

    if not os.path.exists(f'/root/autodl-tmp/VAD/{feature_dir}/30/' + video_name[0] + '.npy'):
        inputs = _load_and_transform_data(batch_clip_frame_paths)
        search_vectors_all = _calculate_search_vectors(inputs)
        faiss.normalize_L2(search_vectors_all)
        np.save(f'/root/autodl-tmp/VAD/{feature_dir}/30/' + video_name[0] + '.npy',
                search_vectors_all)

    else:
        search_vectors_all = np.load(f'/root/autodl-tmp/VAD/{feature_dir}/30/' + video_name[0] + '.npy')


    select_frames = select_flexible_interval_items(frame_path_list)
